package v1beta1

import (
	"context"
	"testing"

	"github.com/openshift/multiarch-tuning-operator/api/common/plugins"
)

func TestValidateCreate_DuplicateArchitectures(t *testing.T) {
	tests := []struct {
		name      string
		cppc      *ClusterPodPlacementConfig
		expectErr bool
	}{
		{
			name: "nil plugins passes validation",
			cppc: &ClusterPodPlacementConfig{},
			expectErr: false,
		},
		{
			name: "nil NodeAffinityScoring passes validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{},
				},
			},
			expectErr: false,
		},
		{
			name: "unique architectures passes validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "amd64", Weight: 50},
								{Architecture: "arm64", Weight: 50},
							},
						},
					},
				},
			},
			expectErr: false,
		},
		{
			name: "duplicate architectures fails validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "amd64", Weight: 50},
								{Architecture: "amd64", Weight: 80},
							},
						},
					},
				},
			},
			expectErr: true,
		},
		{
			name: "single architecture passes validation",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "arm64", Weight: 100},
							},
						},
					},
				},
			},
			expectErr: false,
		},
	}

	v := &ClusterPodPlacementConfigValidator{}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, err := v.ValidateCreate(context.Background(), tt.cppc)
			if tt.expectErr && err == nil {
				t.Error("expected error but got nil")
			}
			if !tt.expectErr && err != nil {
				t.Errorf("expected no error but got: %v", err)
			}
		})
	}
}

func TestValidateUpdate_DuplicateArchitectures(t *testing.T) {
	old := &ClusterPodPlacementConfig{}

	validCPPC := &ClusterPodPlacementConfig{
		Spec: ClusterPodPlacementConfigSpec{
			Plugins: &plugins.Plugins{
				NodeAffinityScoring: &plugins.NodeAffinityScoring{
					Platforms: []plugins.NodeAffinityScoringPlatformTerm{
						{Architecture: "amd64", Weight: 50},
						{Architecture: "arm64", Weight: 50},
					},
				},
			},
		},
	}

	invalidCPPC := &ClusterPodPlacementConfig{
		Spec: ClusterPodPlacementConfigSpec{
			Plugins: &plugins.Plugins{
				NodeAffinityScoring: &plugins.NodeAffinityScoring{
					Platforms: []plugins.NodeAffinityScoringPlatformTerm{
						{Architecture: "s390x", Weight: 50},
						{Architecture: "s390x", Weight: 80},
					},
				},
			},
		},
	}

	v := &ClusterPodPlacementConfigValidator{}

	t.Run("valid update passes", func(t *testing.T) {
		_, err := v.ValidateUpdate(context.Background(), old, validCPPC)
		if err != nil {
			t.Errorf("expected no error but got: %v", err)
		}
	})

	t.Run("duplicate architectures in update fails", func(t *testing.T) {
		_, err := v.ValidateUpdate(context.Background(), old, invalidCPPC)
		if err == nil {
			t.Error("expected error but got nil")
		}
	})
}
